     8→pub fn create_tray<R: Runtime>(app: &AppHandle<R>) -> tauri::Result<()> {
     9→    let toggle_i = MenuItem::with_id(app, "toggle", "Disable", true, None::<&str>)?;
    10→    let separator0 = PredefinedMenuItem::separator(app)?;
    11→    let resume_i = MenuItem::with_id(app, "resume", "Resume", false, None::<&str>)?;
    12→    let pause_30_i = MenuItem::with_id(app, "pause_30", "Pause 30 min", true, None::<&str>)?;
    13→    let pause_60_i = MenuItem::with_id(app, "pause_60", "Pause 1 hour", true, None::<&str>)?;
    14→    let separator1 = PredefinedMenuItem::separator(app)?;
    15→    let settings_i = MenuItem::with_id(app, "settings", "Settings...", true, None::<&str>)?;
    16→    let separator2 = PredefinedMenuItem::separator(app)?;
    17→    let quit_i = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
    18→
    19→    let menu = Menu::with_items(
    20→        app,
    21→        &[
    22→            &toggle_i,
    23→            &separator0,
    24→            &resume_i,
    25→            &pause_30_i,
    26→            &pause_60_i,
    27→            &separator1,
    28→            &settings_i,
    29→            &separator2,
    30→            &quit_i,
    31→        ],
    32→    )?;
    33→
    34→    let icon = Image::from_bytes(include_bytes!("../icons/tray-active.png"))
    35→        .expect("Failed to load tray icon");
    36→
    37→    // Show "DEV" label next to icon in debug builds to distinguish from production
    38→    #[cfg(debug_assertions)]
    39→    let tray_title = Some("DEV");
    40→    #[cfg(not(debug_assertions))]
    41→    let tray_title: Option<&str> = None;
    42→
    43→    let mut builder = TrayIconBuilder::with_id("main")
    44→        .icon(icon)
    45→        .icon_as_template(false)
    46→        .menu(&menu)
    47→        .show_menu_on_left_click(true);
    48→
    49→    // Set title only in dev mode (shows text next to icon on macOS)
    50→    if let Some(title) = tray_title {
    51→        builder = builder.title(title);
    52→    }
    53→
    54→    let _ = builder
    55→        .on_menu_event(move |app, event| {
    56→            // Helper to update pause-related menu items
    57→            let update_pause_menu = |is_paused: bool, remaining: Option<u32>| {
    58→                if is_paused {
    59→                    if let Some(mins) = remaining {
    60→                        let _ = resume_i.set_text(&format!("Resume ({} min left)", mins));
    61→                    } else {
    62→                        let _ = resume_i.set_text("Resume");
    63→                    }
    64→                    let _ = resume_i.set_enabled(true);
    65→                    let _ = pause_30_i.set_enabled(false);
    66→                    let _ = pause_60_i.set_enabled(false);
    67→                } else {
    68→                    let _ = resume_i.set_text("Resume");
    69→                    let _ = resume_i.set_enabled(false);
    70→                    let _ = pause_30_i.set_enabled(true);
    71→                    let _ = pause_60_i.set_enabled(true);
    72→                }
    73→            };
    74→
    75→            // Update menu state when menu event occurs
    76→            {
    77→                let state = app.state::<crate::AppState>();
    78→                let keeper = state.keeper.lock().unwrap();
    79→
    80→                // Update toggle text
    81→                if keeper.is_running() {
    82→                    let _ = toggle_i.set_text("Disable");
    83→                } else {
    84→                    let _ = toggle_i.set_text("Enable");
    85→                }
    86→
    87→                // Update pause status
    88→                update_pause_menu(keeper.is_paused(), keeper.pause_remaining_minutes());
    89→            }
    90→
    91→            match event.id.as_ref() {
    92→                "toggle" => {
    93→                    let state = app.state::<crate::AppState>();
    94→                    let mut keeper = state.keeper.lock().unwrap();
    95→                    if keeper.is_running() {
    96→                        keeper.stop();
    97→                        let _ = toggle_i.set_text("Enable");
    98→                    } else {
    99→                        keeper.start();
   100→                        let _ = toggle_i.set_text("Disable");
   101→                    }
   102→                }
   103→                "resume" => {
   104→                    let state = app.state::<crate::AppState>();
   105→                    let mut keeper = state.keeper.lock().unwrap();
   106→                    keeper.resume();
   107→                    update_pause_menu(false, None);
   108→                }
   109→                "pause_30" => {
   110→                    let state = app.state::<crate::AppState>();
   111→                    let mut keeper = state.keeper.lock().unwrap();
   112→                    keeper.pause(30);
   113→                    update_pause_menu(true, Some(30));
   114→                }
   115→                "pause_60" => {
   116→                    let state = app.state::<crate::AppState>();
   117→                    let mut keeper = state.keeper.lock().unwrap();
   118→                    keeper.pause(60);
   119→                    update_pause_menu(true, Some(60));
   120→                }
   121→                "settings" => {
   122→                    if let Some(window) = app.get_webview_window("main") {
   123→                        let _ = window.show();
   124→                        let _ = window.set_focus();
   125→                    }
   126→                }
   127→                "quit" => {
   128→                    let state = app.state::<crate::AppState>();
   129→                    let mut keeper = state.keeper.lock().unwrap();
   130→                    keeper.stop();
   131→                    drop(keeper);
   132→                    crate::request_exit();
   133→                    app.exit(0);
   134→                }
   135→                _ => {}
   136→            }
   137→        })
   138→        .build(app)?;
   139→
   140→    Ok(())
   141→}
